mapper.select:
SELECT sc.*, c.credit
FROM score sc
LEFT JOIN course c ON sc.course_id = c.id
WHERE 1=1

    AND (sc.student_no LIKE CONCAT('%', #{query.keyword}, '%')
         OR sc.student_name LIKE CONCAT('%', #{query.keyword}, '%'))

AND sc.student_id = #{query.studentId}
AND sc.course_id = #{query.courseId}
AND sc.semester = #{query.semester}
ORDER BY sc.create_time DESC

SELECT sc.*, c.credit
FROM score sc
LEFT JOIN course c ON sc.course_id = c.id
WHERE sc.course_id = #{courseId}
AND sc.semester = #{semester}
ORDER BY sc.score DESC
